package com.korit.clovapi.domain.plan.dto;
import com.korit.clovapi.domain.plan.entity.*; import java.time.*; import java.util.*;
public final class PlanResponses { private PlanResponses(){} public record Writer(String id,String nickname,String profileImageUrl){} public record Checklist(String id,String content,Boolean checked){public static Checklist from(PlanChecklist c){return new Checklist(String.valueOf(c.getId()),c.getContent(),c.getChecked());}} public record Summary(String id,String title,LocalDate planDate,String status,String memoryStatus,Writer writer){public static Summary from(Plan p){return new Summary(String.valueOf(p.getId()),p.getTitle(),p.getPlanDate(),p.getStatus(),p.getMemoryStatus(),PlanResponses.writer(p));}} public record Detail(String id,String roomId,Writer writer,String title,LocalDate planDate,String description,String status,String memoryStatus,LocalDateTime completedAt,List<Checklist> checklists,LocalDateTime createdAt){public static Detail from(Plan p,List<PlanChecklist> c){return new Detail(String.valueOf(p.getId()),String.valueOf(p.getRoomId()),PlanResponses.writer(p),p.getTitle(),p.getPlanDate(),p.getDescription(),p.getStatus(),p.getMemoryStatus(),p.getCompletedAt(),c.stream().map(Checklist::from).toList(),p.getCreatedAt());}} public record Items<T>(List<T> items){} public record Stage(String stage,String state,String imageUrl,Writer uploadedBy,LocalDateTime createdAt){} public record Presign(String uploadUrl,String imageUrl,Integer expiresIn){} private static Writer writer(Plan p){return new Writer(String.valueOf(p.getWriterId()),p.getWriterNickname(),p.getWriterProfileImageUrl());} }
